import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Введение в Fabric и создание модов","description":"Краткое знакомство с Fabric и созданием модов для Minecraft: Java Edition.","frontmatter":{"title":"Введение в Fabric и создание модов","description":"Краткое знакомство с Fabric и созданием модов для Minecraft: Java Edition.","authors":["IMB11","itsmiir"],"authors-nogithub":["basil4088"],"files":[]},"headers":[],"relativePath":"ru_ru/1.21.10/develop/getting-started/introduction-to-fabric-and-modding.md","filePath":"versions/1.21.10/translated/ru_ru/develop/getting-started/introduction-to-fabric-and-modding.md","lastUpdated":1766682904000}`);var a={name:`ru_ru/1.21.10/develop/getting-started/introduction-to-fabric-and-modding.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Введение в Fabric и создание модов <a class="header-anchor" href="#h1" aria-label="Permalink to “Введение в Fabric и создание модов”">​</a></h1><h2 id="prerequisites" tabindex="-1">Предварительные условия <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “Предварительные условия”">​</a></h2><p>Перед тем как начать, вам следует иметь базовые знания разработки на Java и понимание концепций объектно-ориентированного программирования (ООП).</p><p>Если эти концепции вам не знакомы, рекомендуем сначала изучить несколько учебных материалов по Java и ООП. Эти ресурсы могут помочь:</p><ul><li><a href="https://www.w3schools.com/java/" target="_blank" rel="noreferrer">W3: уроки по Java</a>;</li><li><a href="https://www.codecademy.com/learn/learn-java" target="_blank" rel="noreferrer">Codecademy: выучите Java</a>;</li><li><a href="https://www.w3schools.com/java/java_oop.asp" target="_blank" rel="noreferrer">W3: Java в ООП</a>;</li><li><a href="https://medium.com/@Adekola_Olawale/beginners-guide-to-object-oriented-programming-a94601ea2fbd" target="_blank" rel="noreferrer">Medium: введение в ООП</a>.</li></ul><h3 id="terminology" tabindex="-1">Терминология <a class="header-anchor" href="#terminology" aria-label="Permalink to “Терминология”">​</a></h3><p>Прежде чем начнём, давайте рассмотрим некоторые термины, с которыми вы столкнётесь при создании мода на Fabric:</p><ul><li><strong>Мод</strong>: изменение игры, добавляющее новые функции или изменяющее существующие;</li><li><strong>Загрузчик модов</strong>: инструмент для загрузки модов в игру, такой как Fabric Loader;</li><li><strong>Миксин</strong>: инструмент для модификации кода игры во время её выполнения — подробнее в <a href="https://fabricmc.net/wiki/tutorial:mixin_introduction" target="_blank" rel="noreferrer">знакомстве с миксинами</a>;</li><li><strong>Gradle</strong>: инструмент автоматизации сборки, применяемый для создания и компиляции модов. Fabric использует его для сборки своих модов;</li><li><strong>Маппинги</strong>: набор маппингов, преобразующих обфусцированный код в тот, который может прочесть человек;</li><li><strong>Обфускация</strong>: процесс усложнения кода для его затруднённого понимания, используемый Mojang для защиты кода Minecraft;</li><li><strong>Ремаппинг</strong>: процесс преобразования обфусцированного кода в тот, который будет читаем для людей.</li></ul><h2 id="what-is-fabric" tabindex="-1">Что такое Fabric? <a class="header-anchor" href="#what-is-fabric" aria-label="Permalink to “Что такое Fabric?”">​</a></h2><p>Fabric — лёгкий инструмент для создания модов для Minecraft: Java Edition.</p><p>Он разработан как простая и удобная платформа для разработки модов. Fabric — это проект, который ведёт сообщество, и у него открытый исходный код, что означает, что любой может внести в него свой вклад.</p><p>Вам следует знать о четырёх основных компонентах Fabric:</p><ul><li><strong>Fabric Loader</strong>: гибкий загрузчик модов, не зависящий от платформы, предназначенный для Minecraft и других игр и приложений;</li><li><strong>Fabric Loom</strong>: плагин для Gradle, позволяющий разработчикам легко разрабатывать и отлаживать моды;</li><li><strong>Fabric API</strong>: набор API и инструментов для разработчиков модов, которые можно использовать при создании модов;</li><li><strong>Yarn</strong>: набор открытых маппингов Minecraft, свободных для использования под лицензией Creative Commons Zero.</li></ul><h2 id="why-is-fabric-necessary-to-mod-minecraft" tabindex="-1">Почему Fabric необходим для модификации Minecraft? <a class="header-anchor" href="#why-is-fabric-necessary-to-mod-minecraft" aria-label="Permalink to “Почему Fabric необходим для модификации Minecraft?”">​</a></h2><blockquote><p>Модификация игры — это процесс изменения игры с целью изменения её поведения или добавления новых возможностей. В случае Minecraft это может включать в себя всё, от добавления новых предметов, блоков или существ до изменения механик игры или добавления новых режимов игры.</p></blockquote><p>Minecraft: Java Edition обфусцирован компанией Mojang, что делает самостоятельное модифицирование сложным. Однако с помощью инструментов для модификации, таких как Fabric, процесс становится намного проще. Существуют различные системы маппинга, которые могут помочь в этом процессе.</p><p>Loom преобразует обфусцированный код в читаемый формат с помощью этих маппингов, что облегчает мододелам понимание и изменение кода игры. Yarn является популярным и отличным выбором для маппинга, но также существуют и другие варианты. Каждый проект маппинга может иметь свои собственные достоинства и фокусироваться на различных аспектах.</p><p>Loom позволяет с лёгкостью разрабатывать и компилировать моды на основе кода, над которым провели ремаппинг, а Fabric Loader позволяет загружать эти моды в игру.</p><h2 id="what-does-fabric-api-provide-and-why-is-it-needed" tabindex="-1">Что даёт Fabric API и зачем это нужно? <a class="header-anchor" href="#what-does-fabric-api-provide-and-why-is-it-needed" aria-label="Permalink to “Что даёт Fabric API и зачем это нужно?”">​</a></h2><blockquote><p>Fabric API — это набор API и инструментов для разработчиков модов, которые можно использовать при создании модов.</p></blockquote><p>Fabric API предоставляет широкий набор API, которые расширяют существующие функциональные возможности Minecraft. Например, он предлагает новые хуки и события, которые могут использоваться мододелами, или новые утилиты и инструменты, упрощающие процесс модификации игры, такие как транзитивные расширители доступа и возможность доступа к внутренним реестрам, таким как реестр предметов, которые можно использовать в компостнице.</p><p>Хотя Fabric API предлагает довольно мощные функции, некоторые задачи, такие как базовая регистрация блоков, можно выполнять и без него, используя стандартные API Minecraft.</p>`,22)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};